import { getPitchRange } from "../appData.js";

export const level1 = {
  num: 1, name: "Breath & Body", focus: "Diaphragm, posture, SOVT warm-ups, vocal fold health",
  duration: "40 min",
  setup: "Standing. Glass of water. No guitar. Quiet room. Cocktail straw nearby.",
  subtitle: "The Instrument Itself",
  description: "Every great singer built on this foundation. Your voice is not just your throat — it is your entire body, from the arches of your feet to the crown of your head. Unlike every other instrument, there is no fretboard between your intention and the sound — just your body. Every note you will ever sing lives in a specific place in your body: low notes rumble behind the sternum, mid-range notes warm the throat and jaw, high notes buzz in the mask and forehead. This level is about discovering where those places are. Breath support, posture, resonance placement, and warm-ups are the invisible skills that make everything else possible — and they all come down to one thing: learning to feel your instrument from the inside. The cycle that will guide your entire vocal journey begins here: HEAR a sound in your mind, FEEL where it lives in your body, PRODUCE it, COMPARE what happened to what you intended. These exercises set up your body as the instrument before you ask it to play. Think of this level as meeting your voice for the first time with real curiosity — not trying to sound good, just learning how it all works.",
  artists: "Every pro vocalist — from Ella Fitzgerald to Eddie Vedder, from Tinariwen to Khruangbin's Mark Speer humming over desert grooves",
  unlocks: "Tuning the Instrument (Level 2)",
  exercises: [
    {
      id: "v1e0", time: 5, title: "Where Are You Right Now? — Diagnostic Pre-Test", type: "record",
      what: "Before training anything, capture an honest snapshot of where your voice is today. This is your baseline — you will come back to this recording after completing Level 1 and hear the difference. No judgment, just data. This recording is for you alone.",
      setup: "Standing. Recorder on. No warm-up — we want the raw, unwarmed state. Glass of water nearby.",
      recorder: true,
      referencePitches: getPitchRange("E3", "A3"),
      pianoKeys: { notes: ["C3", "E3", "G3", "A3"], label: "Vocal Range", range: ["C3", "A3"] },
      steps: [
        { text: "Before anything else: what ONE thing are you most curious about regarding your voice right now? Hold that question in mind. Then take three natural breaths. Don't try to breathe 'correctly' — just breathe the way you normally do. Notice where the breath goes: chest? belly? shoulders?", why: "Your default breathing pattern reveals your starting point. Most untrained singers breathe into their upper chest, which creates tension and limits breath support. There is no wrong answer here — just honest observation. Your brain needs to register the 'before' state so it can recognize change later. This is what motor learning researchers call establishing a baseline — without it, progress feels invisible." },
        { text: "Place one hand on your belly, one on your chest. Take five breaths and notice which hand moves more. Say out loud: 'My [chest/belly] moves more.'", why: "Naming what you observe makes it conscious. Most people have never paid attention to their breathing mechanics. The belly hand moving more suggests diaphragmatic tendency; the chest hand moving more suggests accessory muscle breathing. Neither is 'wrong' for daily life, but singing demands diaphragmatic control. By saying it out loud, you are encoding the observation into memory through multiple pathways — visual, kinesthetic, and auditory." },
        { text: "Sing 'Happy Birthday' at a comfortable volume. Don't try to sound good — sing it the way you would at an actual birthday party. Record the whole thing.", why: "This familiar melody removes the cognitive load of learning new music, so your voice reveals its natural habits. The recording captures your default tone, pitch accuracy, breath patterns, and where you naturally pause for air. In six weeks, you will listen back to this and be genuinely surprised at how much has changed. Every vocal coach uses baseline recordings because human memory is unreliable — we forget how we used to sound." },
        { text: "Now sustain an 'ahh' on a comfortable note for as long as you can. Time it. Write down the number of seconds.", why: "Maximum phonation time (MPT) is a clinical measure of vocal efficiency. Untrained singers typically sustain 15-20 seconds. With proper breath support, 25-35 seconds is achievable. This number will improve as your rib expansion and appoggio technique develop. It is one of the most objective measures of vocal progress, used by speech-language pathologists and vocal coaches alike." },
        { text: "Slide from your lowest comfortable note up to your highest on a 'wee' sound. Don't push — stop when it feels strained. Note your approximate low and high notes.", why: "This maps your current functional range. Not your theoretical range, but the range you can access today without warm-up. Your range will expand as your technique improves, but more importantly, the QUALITY of notes in your existing range will improve dramatically. Most singers gain more from improving tone quality in their current range than from chasing higher notes." },
        { text: "Stand naturally and look at yourself in a mirror (or take a photo). Notice: are your shoulders level? Is your head tilted? Is your jaw clenched? Where do you hold tension?", why: "Postural habits are invisible until you look. Tension patterns in your shoulders, neck, and jaw directly affect vocal production. A forward head posture shortens the vocal tract. Elevated shoulders compress the ribcage. A clenched jaw restricts resonance. Identifying your specific tension patterns lets you target them in the exercises that follow. Singers who address their individual postural issues improve faster than those who follow generic advice." },
        { text: "Say: 'I am starting vocal training on [today's date]. My sustained note lasted [X] seconds. My comfortable range is roughly [low note] to [high note].' Record this statement.", why: "This spoken timestamp creates an emotional anchor. When you revisit this recording after completing all ten levels, hearing your own voice state the date and baseline will make your progress viscerally real. The act of committing to training out loud — hearing yourself say it — activates a different level of intention than just thinking it. Researchers call this a public commitment effect, and it measurably increases follow-through." },
        { text: "Save this recording somewhere you will not lose it. Label it 'Vocal Baseline — Level 1 Start.' You will need it later. Before you move on, end with one thing that felt good — even just one breath that felt natural. Your brain encodes the ending of each session as the summary of the whole experience.", why: "The comparison between this recording and your Level 10 recording will be one of the most satisfying moments in your vocal journey. Protect this artifact. It represents the courage to start, which is the hardest part of any skill acquisition. Ending on a positive moment leverages the peak-end rule — your brain remembers the ending disproportionately, so a good ending creates motivation to return." }
      ],
      feel: "This should feel like a doctor's checkup — neutral, observational, no performance pressure. You are gathering data, not auditioning. If you feel self-conscious, that is completely normal. Every singer who has ever trained started with this same vulnerable moment of honest assessment.",
      wrong: "If you find yourself trying to sound impressive on the recording, start over. The diagnostic only works if it captures your actual starting point. Faking a better baseline just robs you of the satisfaction of real progress later. Also: don't skip the timing on the sustained note. That number matters. Whatever you hear on this recording, remember: this is your starting line, not your ceiling. Awkwardness here is just the sound of a singer who hasn't been trained yet.",
      sarah: "I do this with every new student. The recording is sacred — it is proof of where you started. Six months from now you will listen back and not believe it is the same person. You chose to start this — that matters more than any vocal technique. The fact that you are here, doing this exercise, means you are already ahead of 90% of people who 'want to sing better' but never actually start.",
      levelUp: "Completed all recordings and written notes. You have a clear, honest baseline."
    },
    {
      id: "v1e1", time: 4, title: "\"Hey, Stop It!\" — Chest Voice Activation", type: "vocal",
      what: "Use conversational exclamations to naturally engage your chest voice and diaphragm. Your chest voice is the foundation of your singing instrument — it is the register you speak in, and the register that gives your singing warmth, weight, and emotional grounding. This exercise uses everyday speech patterns to activate it without overthinking.",
      setup: "Standing. Hand on belly, skin contact under your shirt. Other hand on your chest, above the sternum.",
      referencePitches: getPitchRange("F3", "B3"),
      pianoKeys: { notes: ["C3", "E3", "G3", "A3"], label: "Vocal Range", range: ["C3", "A3"] },
      recorder: true,
      steps: [
        { text: "Say 'Hey!' like someone across the room just did something annoying — loud, natural, conversational. Not singing, just talking. Do it three times. Notice where the sound lives in your body: you should feel a pulse low in your torso, behind the sternum, vibrating through your ribs.", why: "This engages your diaphragm without thinking about it. Natural speech activates chest voice automatically because your brain already knows how to produce these sounds. You have been using chest voice in conversation your entire life — the trick is recognizing it and learning to access it deliberately. The diaphragm contracts and pushes the belly outward to generate the subglottic pressure needed for a projected 'Hey!' Your nervous system does this reflexively; we are just making it conscious." },
        { text: "Feel your belly push against your hand? That is your diaphragm contracting. That is chest voice. Now say 'Hey!' again and really focus on that belly push. The push should happen BEFORE the sound comes out, not during. The vibration lives low — behind the sternum, spreading through the ribs. This is your chest voice body address: E3 to A3, the warm rumble zone.", why: "The belly push is the diaphragm descending, which compresses the air below the vocal folds (subglottic pressure). This is the foundation of breath support. The timing matters — the diaphragm should engage a split second before phonation begins. This pre-phonatory pressure is what separates supported singing from throat-squeezed singing. Trained singers activate the diaphragm 50-200 milliseconds before the sound starts. You are training that same anticipatory pattern right now." },
        { text: "Now say 'Hey' softly, gently, like whispering to a baby. Notice: no belly push. The sound feels lighter, higher, floatier. Put your hand on the top of your head — you might feel a subtle vibration there. The vibration has migrated upward from your chest to your forehead and crown. This is head voice — it lives above the jaw, in the mask and skull.", why: "Head voice feels lighter because the vocal folds are stretched thinner and vibrate along their edges rather than their full mass. The sound resonates in the upper cavities of your skull rather than your chest cavity. Neither register is better — they are different colors on your palette. DOPE LEMON's Angus Stone lives in this breathy, heady space. Allah-Las use chest voice for their garage-rock warmth. You need both." },
        { text: "Say 'Hey, stop it!' — commit to it, like you genuinely mean it, like someone is about to knock over your amp. Full conviction. That is full chest voice engagement.", why: "The exclamation forces diaphragm engagement because your nervous system treats it as an urgent communication. It is not about volume — it is about engagement and intent. A whispered 'stop' can be chest voice if the diaphragm is engaged. The intent behind the sound determines the register more than the volume. This is why acting training and vocal training overlap — your body responds to emotional commitment." },
        { text: "Alternate rapidly: loud 'Hey!' (chest) then quiet 'hey' (head) then loud 'Hey, STOP IT!' (chest). Do this five times. Feel the flip between registers — that internal switch. Track where the vibration jumps: sternum for chest, forehead for head, sternum again. Your body is the map — each register has a home address.", why: "Training the switch between registers builds awareness of the muscular difference. In chest voice, the thyroarytenoid muscles (inside the vocal folds) are thick and engaged. In head voice, the cricothyroid muscles stretch the folds thin. You are learning to feel this difference so you can eventually control the blend between them. This flip will become the foundation of your mix voice later in Level 2." },
        { text: "Now sustain a note on 'Hey' — pick a comfortable pitch around G3. Hold it for five seconds. Keep your hand on your belly and feel the sustained diaphragm engagement.", why: "Moving from speech to sustained pitch is the bridge between talking and singing. The diaphragm engagement should feel the same whether you are saying 'Hey!' or singing 'Hey' on a pitch. If the belly push disappears when you start singing, you have disconnected from your breath support — the most common beginner mistake. Sustained phonation requires sustained diaphragmatic pressure, not a single burst." },
        { text: "Sing 'Hey, stop it!' on a descending three-note pattern: G3-F3-E3. The words should sound natural, like speech that happens to be on pitch. Do this three times.", why: "This is your first moment of actual singing in the curriculum, and it is designed to feel like talking. The best vocal tone — especially for the laid-back psych-surf aesthetic you love — comes from a voice that sounds like it is speaking on pitch, not 'performing.' Singers like Matt Flegel of Preoccupations or Angus Stone sound compelling because they barely distinguish between their speaking and singing voice. That natural quality starts here." },
        { text: "Record yourself doing the spoken 'Hey!' and the sung version back to back. Listen: do they have the same weight, the same belly engagement? Or does the sung version sound thinner? What ONE thing did you notice about the difference between speaking and singing?", why: "Self-recording closes the feedback loop. Your internal perception of your voice is dramatically different from what others hear. The bones of your skull conduct low frequencies directly to your inner ear, making your voice sound deeper to you than it actually is. Listening to recordings trains your brain to calibrate its internal model against external reality. If the sung version sounds thinner than the spoken version, you are losing breath support when you switch to singing mode — a very common pattern that we will fix." }
      ],
      feel: "When you nail chest voice, your whole torso resonates — the sternum buzzes, the ribs hum, the sound lives in the low chest zone (E2-A3 on the vibration-rising map). It should feel like the sound is coming from your gut, not your throat. Your belly stays engaged, your throat stays relaxed, and the sound has a warmth and weight to it. Head voice feels like the sound floats above your shoulders — lighter, airier, the vibration migrating up toward the mask and forehead. The key insight is that volume and register are independent — you can be loud in head voice and quiet in chest voice. Notice: you are already mapping your body as the instrument. Each register has a body address.",
      wrong: "If 'Hey, stop it!' feels like you are just getting louder without the belly engagement, you are pushing from your throat. Think of getting punched in the stomach — that instinctive flex is the same muscle activation you want for chest voice. If your throat feels sore after this exercise, you are definitely throat-pushing — and that is a perfectly normal first attempt, not a sign you are doing something wrong. Your body is learning a new coordination. The sound should never feel effortful in your throat. All the effort lives below your collarbones.",
      sarah: "It is not even just a volume thing — it is an engagement of that diaphragm muscle down there. People think belting is yelling, but belting is from a mixed voice. If you can mix it, you can have a huge voice. But it all starts with clean chest voice activation. And here is the thing — the singers you love, like Mark Speer humming those Khruangbin melodies or the Allah-Las' laid-back delivery, they are all in chest voice most of the time. That warm, grounded, effortless quality IS chest voice done right.",
      levelUp: "Can clearly feel and identify chest vs head voice on command. Sustained sung note has the same belly engagement as the spoken exclamation."
    },
    {
      id: "v1e2", time: 4, title: "Rib Expansion Breathing — Appoggio", type: "vocal",
      volumeMeter: true,
      what: "Appoggio technique: your ribs expand sideways and stay expanded during exhale. This is the breath support technique used by trained singers from Italian opera to Jamaican reggae. The intercostal muscles between your ribs are the key — they maintain the expanded ribcage while the diaphragm controls the exhale rate. Sustain 'sss' for increasing durations to build this endurance.",
      setup: "Standing. Hands on sides of ribcage, fingers pointing forward, thumbs wrapping around to your back ribs. You should feel both the front and side expansion.",
      steps: [
        { text: "Place hands on your ribcage, fingers forward, thumbs back. Breathe in slowly through your nose for a count of four. Feel your ribs push your hands outward — not your chest rising, not your belly pushing out, but your ribs expanding sideways like an accordion.", why: "Lateral rib expansion is the foundation of appoggio, the breath support technique that has been taught in Italian vocal pedagogy for over 400 years. The word 'appoggio' literally means 'to lean' — you are leaning the voice against a column of supported air. The diaphragm descends and flattens, the lower ribs flare outward, and the intercostal muscles between the ribs engage to maintain this expanded position. This is fundamentally different from belly breathing or chest breathing. Belly breathing alone moves the belly but does not engage the intercostals. Chest breathing raises the shoulders and creates tension. Appoggio does neither — it expands the ribcage laterally and holds it there." },
        { text: "Keep your ribs expanded and exhale on a sustained 'sss' sound — like a tire slowly leaking. The key instruction: do NOT let your ribs collapse. They stay pushed outward against your hands even as air leaves your body.", why: "This is the counterintuitive part that confuses every new singer: the ribs stay OUT while you exhale. Your instinct is to let everything collapse when you breathe out, but in appoggio, the intercostal muscles resist that collapse. This creates a controlled, steady airflow that gives the vocal folds exactly the amount of air they need — not too much (which causes breathiness) and not too little (which causes strain). Think of it like a hydraulic system: the expanded ribs create back-pressure that regulates the air release. Opera singers, Broadway performers, and reggae singers like Bob Marley all used this same principle, whether they called it appoggio or not." },
        { text: "Sustain 'sss' for 10 seconds on your first attempt. Keep a clock visible. If your ribs collapse before 10 seconds, that is your current limit — no judgment, just data. Rest for 10 seconds.", why: "Ten seconds of sustained 'sss' is achievable for most beginners and gives you a clear target. The 'sss' sound is ideal for breath support training because it requires steady airflow without involving the vocal folds — isolating the breathing mechanism from the vocal mechanism. If your ribs collapse at 7 seconds, that tells you exactly where your intercostal endurance currently lives. These muscles respond to training just like any other muscle group, and they respond fast — most students add 5-10 seconds within the first week." },
        { text: "Second round: aim for 15 seconds. Same steady 'sss', same rib expansion. If the 'sss' starts wavering or getting louder/quieter, your support is failing. Reset and try again.", why: "The quality of the 'sss' is more important than the duration. A perfectly steady, even 'sss' for 12 seconds is better than a wobbling, uneven 'sss' for 20 seconds. Wavering means your intercostals are fatiguing and the diaphragm is taking over in bursts rather than maintaining steady pressure. This uneven airflow is what causes pitch wobble, dynamic inconsistency, and that 'running out of air' feeling mid-phrase. By training a steady 'sss', you are building the foundation for steady, controlled singing." },
        { text: "Third round: aim for 20 seconds. This is where it gets challenging. Your intercostals may start to burn slightly — that is normal muscle engagement, not pain. If you feel actual pain, stop.", why: "Twenty seconds of sustained, supported airflow is enough to sing most phrases in popular music without taking a breath. The Bee Gees' long phrases, Jeff Buckley's sustained notes, the extended chanting of Tinariwen — all require this kind of breath support endurance. The slight burn you feel is the intercostal muscles working against the natural elastic recoil of the ribcage, which wants to spring back to its resting position. You are training them to resist that recoil. This is exactly like holding a plank — the muscles work isometrically, holding a position against a force that wants to collapse them." },
        { text: "Now combine the rib expansion with the diaphragm awareness from v1e1. Breathe in with rib expansion. Say 'Hey!' and feel BOTH the belly push AND the ribs staying expanded. This is full breath support.", why: "In exercise v1e1, you learned to feel the diaphragm engage on speech. Now you are adding the rib expansion on top of it. Full breath support uses both systems simultaneously: the diaphragm provides the driving pressure from below, and the expanded ribcage provides the regulation from the sides. It is like a car with both an engine (diaphragm) and brakes (intercostals) — you need both to drive smoothly. Without the ribs, the diaphragm can only produce bursts of pressure. Without the diaphragm, the ribs can only hold static air. Together, they create the controlled, steady, powerful airflow that makes great singing possible." },
        { text: "Sustain a hum on a comfortable note (around G3) while maintaining rib expansion. Hold for 10 seconds. The hum should be perfectly steady — no wavering in pitch or volume.", why: "This bridges the gap between the breathing exercise and actual singing. The hum adds vocal fold vibration to the breath support equation. If your rib expansion collapses when you start humming, your body has not yet integrated the two skills. The hum should feel almost passive — like the air does the work and the vocal folds just vibrate in the stream. This 'passive phonation on active support' is the holy grail of vocal technique. It is what makes some singers sound effortless while others sound like they are working hard." },
        { text: "Final challenge: alternate between 'sss' (5 seconds) and humming (5 seconds) three times in a row, all on one breath, all with ribs expanded. Total: 30 seconds of sustained output. Then set this down for 60 seconds — check your water, look out the window — and try it once more from memory. That second attempt, without the warmth of repetition, is where the real learning locks in.", why: "This integration exercise proves that your breath support system works regardless of whether the vocal folds are engaged or not. The 'sss' is unvoiced, the hum is voiced, but the breath support underneath is identical. When you can maintain rib expansion through both, switching freely between them, your body has learned to separate breathing from voicing — a critical coordination that most untrained singers have never developed. This separation is what allows trained singers to breathe independently of their vocal choices." }
      ],
      feel: "Your ribs should feel like a barrel that stays inflated even as air leaves. The 'sss' should be perfectly steady — no wavering, no bursts. When you add the hum, it should feel like the sound is riding on a cushion of air. Your throat should feel completely uninvolved — all the work is happening in your torso.",
      wrong: "If your shoulders rise when you breathe in, you are chest breathing — reset and focus on lateral rib movement only. If your ribs collapse immediately on exhale, you have not engaged the intercostals yet. Start with shorter durations and really focus on the feeling of ribs pushing outward against your hands. If you feel dizzy, you are hyperventilating — take fewer breaths and let your body normalize between rounds.",
      sarah: "Breath support is not about taking a big breath. It is about controlling the release. The ribs staying out IS the support. I see students take these huge gasping breaths and then wonder why they still run out of air mid-phrase. It is never about how much air you take in — it is about how efficiently you let it out. A singer with great appoggio can sing a full phrase on half a breath because none of that air is wasted. Try experimenting with how LITTLE air you can use and still sustain the sound — you might surprise yourself.",
      levelUp: "Sustain 'sss' for 20 seconds with steady airflow and ribs staying expanded. Successfully alternate 'sss' and hum on a single breath for 30 seconds."
    },
    {
      id: "v1e3", time: 4, title: "Vagal Warm-Up Protocol — Humming for Calm", type: "vocal",
      what: "A structured humming sequence designed to activate your vagus nerve and shift your nervous system into a calm, focused state before singing. Humming is one of the most effective ways to stimulate the vagus nerve, which runs from your brainstem through your throat and into your abdomen. When activated, it shifts you from fight-or-flight (sympathetic) into rest-and-digest (parasympathetic) — the state where your best singing happens.",
      setup: "Standing or seated comfortably. Hands resting on your thighs. Eyes can be closed. No audience, no pressure.",
      referencePitches: getPitchRange("C3", "G3"),
      pianoKeys: { notes: ["C3", "E3", "G3", "A3"], label: "Vocal Range", range: ["C3", "A3"] },
      steps: [
        { text: "Close your eyes. Take three slow breaths: inhale for 4 counts, exhale for 6 counts. The exhale being longer than the inhale is the key — do not rush it. As you exhale, feel the vibration of the breath settling low in your body — belly, lower ribs, the base of the ribcage. Before any sound begins, this is where your voice lives: deep in the body's center.", why: "Extended exhale breathing is the fastest way to activate the parasympathetic nervous system via the vagus nerve. The vagus nerve is the longest cranial nerve in your body, running from your brainstem all the way down to your gut. When you exhale slowly, the vagus nerve signals your heart to slow down, your muscles to relax, and your vocal folds to release tension. This is why you instinctively sigh when you are relieved — your body is self-regulating through vagal activation. For singing, this state is essential because laryngeal tension (tight throat) is almost always caused by sympathetic (fight-or-flight) activation. You cannot sing freely when your body thinks it is under threat." },
        { text: "Begin humming on a low, comfortable note — around C3 or D3. Before you hum, hear the note in your mind for 2 seconds — imagine its specific pitch and WHERE it will vibrate. Then hum with your lips gently closed, jaw slightly dropped behind your lips, tongue resting on the floor of your mouth. Sustain for 8-10 seconds. Feel the vibration settle behind your sternum and spread into your ribs — C3 lives deep in the chest, a warm rumble that you feel more than hear.", why: "Humming creates vibration in the nasal cavity, sinuses, and skull bones. This vibration directly stimulates the vagus nerve where it passes through the throat. Research from the International Journal of Yoga found that 'Om' chanting (which is essentially humming) increases vagal tone and reduces anxiety. You do not need to chant Om — any sustained hum produces the same physiological effect. The key is that the vibration must be felt in your face and head, not just heard. If you can feel your nose and forehead buzzing, the vagus nerve is being stimulated." },
        { text: "Move the hum to D3, then E3, then back to D3, then C3. Spend 5 seconds on each note. Smooth transitions — no gaps between notes. As the pitch rises from C3 to E3, feel the vibration climb — from the deep sternum rumble of C3 to the upper chest and throat warmth of E3. As you descend, the vibration pours back down. You are tracing the beginning of your vibration-rising body map.", why: "Gentle pitch changes while humming engage the cricothyroid and thyroarytenoid muscles in a low-stress way. These are the same muscles that control pitch during singing, but the hum provides SOVT (semi-occluded vocal tract) backpressure that protects the folds from strain. Moving through a small range ensures these muscles warm up gradually. Think of it as a warm-up for your warm-up — preparing the delicate vocal fold musculature for the more demanding exercises ahead. Cold vocal folds are stiff and more susceptible to injury, just like cold muscles in any athletic context." },
        { text: "Now add a physical element: while humming on E3, place your fingertips on your cheekbones and feel the vibration. Move your fingers to your forehead. Then to the bridge of your nose. Map where the vibration is strongest.", why: "Resonance mapping builds your somatosensory awareness — your ability to feel where sound vibrates in your body. Trained singers rely on physical sensation more than they rely on hearing to monitor their voice. Research from the Voice Foundation shows that experienced singers make 76% of their vocal adjustments based on how the sound FEELS, not how it sounds to their ears. This is a critical insight: your ears can deceive you (room acoustics, monitor mix, audience noise), but the feeling of resonance in your face is always available and always accurate. By mapping vibration now, you are building the sensory vocabulary you will use throughout your training." },
        { text: "Shift the hum to an 'mmm' with a slight opening: 'mmmm-aaahhhh.' Start with the hum, then slowly open your mouth to 'ah' without changing the pitch. Feel how the vibration moves from your nose to your mouth.", why: "This 'hum-to-open' transition is one of the most important techniques in vocal pedagogy. It teaches you to maintain the resonance placement of the hum while opening to a full vowel. Many singers lose all their resonance the moment they open their mouth because they have not learned to carry the 'forward buzz' from the hum into the open vowel. The vibration should stay in your face — behind your nose, in your cheekbones — even when your mouth is wide open. This forward placement is what gives voices like Mark Speer's hummed melodies or DOPE LEMON's relaxed vocals that warm, present quality." },
        { text: "Repeat the hum-to-open on three pitches: C3, E3, G3. On each pitch, sustain the hum for 5 seconds, then open to 'ah' for 5 seconds. Notice if the vibration stays in the same place when you open.", why: "Practicing on multiple pitches ensures the technique is not pitch-dependent. Each pitch resonates slightly differently in the vocal tract, and the 'forward placement' feeling may be easier on some notes than others. C3 tends to resonate more in the chest, G3 more in the head, and E3 is a blend. Learning to maintain forward placement across all three teaches your muscles to generalize the technique. This is how motor learning works — practicing a skill in varied conditions creates more robust, transferable learning than practicing in a single condition." },
        { text: "Final step: sit in the resonance. Hum a comfortable note for 20 seconds with your eyes closed. Focus entirely on the physical sensation — the buzz in your nose, the warmth in your chest, the vibration in your skull. Do not think about pitch or tone. Just feel.", why: "This meditative humming is your vagal activation peak. Twenty seconds of sustained humming with focused attention on sensation shifts your nervous system fully into parasympathetic mode. Your heart rate drops, your laryngeal muscles release excess tension, and your vocal folds reach their optimal resting state for phonation. Many professional singers use this exact technique backstage before performances — not vocal scales, not power warm-ups, but simple, sustained humming with eyes closed. It works because it simultaneously warms up the voice AND calms the nerves. You are training your body to associate singing with calm focus rather than anxiety and performance pressure." }
      ],
      feel: "After this exercise, your voice should feel 'ready' without feeling 'pushed.' Your throat should feel open and loose. Your face should feel slightly buzzy, like you have been massaging it from the inside. Your breathing should be slower and deeper than when you started. There should be a sense of calm alertness — focused but not tense.",
      wrong: "If you feel tension in your jaw or throat while humming, your jaw is clenched or your tongue is pressed against the roof of your mouth. Drop your jaw behind your closed lips — there should be space between your teeth even though your lips are closed. If the humming feels strange or 'wrong' compared to how you normally use your voice, that is your body map updating — new sensations during vocal work mean the neural pathways are reorganizing, not that you are doing it incorrectly. If you feel no vibration in your face at all, try humming louder or changing pitch slightly — there is a 'sweet spot' where the resonance locks in and the buzz becomes unmistakable.",
      sarah: "I start every lesson with humming. Not because it is a fancy technique — because it literally changes your nervous system state. Your body can not sing freely when it is stressed. The vagus nerve connection is real science, not woo-woo. Humming tells your brain: we are safe, we are calm, we are ready. Every singer I have worked with who struggles with performance anxiety has improved by starting their practice with two minutes of humming. It is almost unfair how effective it is.",
      levelUp: "Can sustain a relaxed hum for 20 seconds with clear facial vibration. The hum-to-open transition maintains forward resonance placement on all three pitches."
    },
    {
      id: "v1e4", time: 4, title: "Lip Trill Warm-Up — SOVT Foundation", type: "vocal",
      pitchContour: true,
      what: "Semi-Occluded Vocal Tract (SOVT) warm-up using lip trills. The backpressure from the trill creates a cushion of air above the vocal folds, helping them vibrate efficiently with less effort. This is the most widely recommended warm-up in modern vocal pedagogy — used by Broadway performers, pop stars, opera singers, and speech therapists. Start on comfortable pitches, glide through a 5th, finish with a relaxed sigh.",
      setup: "Standing. Lips loose — shake them out like a horse. Jaw relaxed and slightly dropped. Cheeks relaxed.",
      referencePitches: getPitchRange("C3", "G3"),
      pianoKeys: { notes: ["C3", "E3", "G3", "A3"], label: "Vocal Range", range: ["C3", "A3"] },
      steps: [
        { text: "What ONE thing will you listen for during these lip trills — smoothness, ease, the passaggio transition? Pick one focus. Then shake your lips loose — blow air through them like a horse ('brrrrr'). Do this three times without adding pitch. Just air through floppy lips.", why: "The lip trill requires relaxed, pliable lip tissue. If your lips are tense (from talking, from stress, from clenching), the trill will not start. The horse-lip warm-up releases the orbicularis oris muscle that circles your lips. This muscle is one of the most chronically tense muscles in the face because it is engaged in all speech. You need it relaxed for the trill to work. This pre-warm-up-warm-up takes 10 seconds and makes the difference between a frustrating trill and an effortless one." },
        { text: "Lips together, loose. Start a lip trill by adding pitch — hum behind the trill on C3. If the trill will not start, press your index fingers gently into your cheeks, pushing the cheek tissue slightly toward your lips. Hold the trill on C3 for 4 seconds.", why: "The lip trill creates SOVT backpressure — the partially closed lips trap air above the vocal folds, creating a cushion that helps the folds vibrate with less effort and less contact force. This is like power steering for your voice: the backpressure does some of the work, so your vocal folds do not have to work as hard. Research from Ingo Titze (the leading voice scientist) shows that SOVT exercises reduce vocal fold collision force by up to 30% while maintaining the same volume output. The cheek-press trick works because it adds mass to the lip tissue, making it easier to vibrate at lower airflows." },
        { text: "Hold the trill on C3 for 4 seconds. Then D3 for 4 seconds. Then E3 for 4 seconds. Each note should feel equally easy. If a note feels harder, reduce your airflow — less air, not more.", why: "Starting on comfortable, low notes warms up the vocal folds gently without strain. The common mistake is using too much air for the trill, which blows the lips apart and stops the trill. SOVT exercises work on LESS air than you expect — the backpressure means the folds need less subglottic pressure to vibrate. If you are using the right amount of air, the trill feels almost passive, like it is happening to you rather than being produced by you. This effortless quality is the goal for all SOVT work." },
        { text: "Before you glide, hear the path in your mind's ear — imagine the pitch rising from C3 to G3 as a smooth arc. Then glide from C3 up to G3 (a perfect 5th) on one continuous trill. Slow and steady, 3-4 seconds for the ascent. Do not rush through the middle — every pitch between C3 and G3 should be visited. As you ascend, feel the vibration migrate from deep chest (C3) through the upper chest (E3) to the throat and jaw (G3). Your body traces the bottom half of the vibration-rising map.", why: "The glide stretches the vocal fold musculature gradually through a moderate range. The cricothyroid muscle (which stretches the folds for higher pitches) engages progressively as you ascend. The SOVT backpressure makes this stretching feel easy and safe, which is why lip trills are the preferred warm-up: they let you move through range without the risk of straining. A straight ascending scale would force the folds to make discrete jumps; a smooth glide allows them to transition continuously, which is gentler on the delicate vocal fold tissue." },
        { text: "Glide back down G3 to C3 on the trill. Repeat the up-down cycle 3 times. Each pass should feel easier than the last — that is the warm-up working.", why: "Each pass loosens the vocal folds a little more. The blood flow to the laryngeal muscles increases with each cycle, making the tissue more pliable. This is literal warming up — the temperature of the vocal fold tissue increases slightly with use, making the mucosal wave (the ripple across the surface of the folds) more efficient. Cold folds are stiff and resist vibration. Warm folds are supple and vibrate freely. Three passes is usually enough to bring the folds to operating temperature. If it still feels stiff after three, do two more." },
        { text: "Expand the range: glide from C3 up to A3 (a 6th). This enters your passaggio zone. Notice if the trill becomes harder to maintain around Ab3-A3. That is normal — the vocal folds are negotiating the register transition.", why: "Extending the glide into the passaggio is a safe way to explore the break zone because the SOVT backpressure supports the transition. Without the trill, gliding through A3 might cause a crack or flip. With the trill, the backpressure stabilizes the vocal folds, allowing them to make the register transition more gradually. You are essentially training the passaggio crossing with training wheels. Over time, as the muscles learn the coordination, you will be able to make the same smooth transition without the trill. But the trill teaches the pattern first." },
        { text: "Finish with a deep, relaxed sigh — 'haaaaah' from the top of your comfortable range down to the bottom. No trill, just an open, loose release. Like you are deflating completely. Do two of these.", why: "The sigh releases any tension that accumulated during the trill exercise. It resets your throat to a neutral, relaxed state. The sigh is also a diagnostic: if your voice feels easier and smoother on the sigh than it did before the trills, the warm-up worked. The contrast between your pre-trill voice and your post-trill voice should be noticeable — more resonance, less effort, smoother transitions. This contrast is your first experience of what a warmed-up voice feels like versus a cold one. Remember this feeling — it is the minimum state your voice should be in before you sing anything." }
      ],
      feel: "The trill should feel buzzy and effortless — like your lips are doing their own thing while your voice just provides gentle airflow. If it feels like work, you are using too much air. Less air equals better trill. The glides should feel smooth, like sliding your hand along a railing. After the exercise, your voice should feel noticeably easier and more resonant than before you started. End on a glide that felt good — let that be the last thing your body remembers.",
      wrong: "If the trill keeps cutting out, three possible causes: (1) too much air — reduce airflow significantly; (2) lips too tense — do the horse-lip shake again; (3) jaw tension — drop your jaw and let it hang loose. If the pitch wobbles during the glide, slow down. Speed is not the goal — smoothness is. If you cannot get the trill to work at all after multiple attempts, switch to a 'vvv' sound (voiced V) which provides similar SOVT benefits without requiring lip vibration.",
      sarah: "Lip trills are the Swiss Army knife of vocal warm-ups. They warm up the folds, they train breath support, they smooth out the passaggio, and they take almost no effort. If you only do one warm-up exercise for the rest of your life, make it lip trills. Every professional singer I know does some version of this. It is not glamorous, but it is the single most efficient use of warm-up time.",
      levelUp: "Clean lip trill glides C3 to G3 and back, 3 times without the trill cutting out. Extended glide to A3 with maintained trill through the passaggio zone."
    },
    {
      id: "v1e5", time: 4, title: "Posture Reset — Body Mapping", type: "vocal",
      what: "Singer's body alignment using principles from the Alexander Technique and body mapping. Your posture directly affects your voice — a forward head shortens the vocal tract, elevated shoulders compress the ribcage, locked knees create full-body tension. This exercise builds the physical setup you should use before every vocal session. It is not about standing 'perfectly' — it is about removing the obstacles that prevent your voice from working freely.",
      setup: "Standing. Bare feet if possible. Mirror or window reflection helps. No guitar.",
      steps: [
        { text: "Feet shoulder-width apart. Knees slightly soft — not bent, just unlocked. Imagine your kneecaps are floating, not rigid. Shift your weight gently forward and back until you find the center — evenly distributed across both feet.", why: "Locked knees create a chain reaction of tension that travels upward through your body. When your knees lock, your pelvis tilts, your lower back compresses, your ribcage restricts, and your throat tightens. This is all connected through the fascial chain — the continuous web of connective tissue that links your feet to your skull. Unlocking your knees is the single most impactful postural change for singing because it releases the entire chain. The Alexander Technique calls this 'undoing' — not adding effort, but removing unnecessary holding. Your body already knows how to stand freely; you just need to stop preventing it." },
        { text: "Roll your shoulders up to your ears as high as they will go. Hold for 3 seconds — really squeeze them up. Then DROP them. Do not lower them slowly — let them fall with gravity. Repeat 3 times.", why: "The contract-and-release technique is the fastest way to reduce shoulder tension because it uses a neurological principle called post-isometric relaxation. When you contract a muscle strongly and then release it, the muscle reflexively relaxes to a state lower than its baseline tension. Three cycles of this typically reduce resting shoulder tension by 40-60%. Shoulder tension is the number one enemy of good singing because elevated shoulders compress the ribcage (reducing breath capacity) and pull on the muscles of the neck and throat (increasing laryngeal tension). Nearly every singer carries excess shoulder tension from daily activities — typing, driving, phone use, guitar playing." },
        { text: "Let your jaw hang open — literally let gravity open it. Do not actively open it. Then massage the jaw hinge (the temporomandibular joint, just in front of your ears) in small circles for 15 seconds. Press gently but firmly.", why: "A tight jaw restricts resonance, limits vowel formation, and creates a cascade of tension into the throat. The TMJ is one of the most commonly tense joints in the body — stress, concentration, and even guitar playing (clenching while focusing) all contribute to chronic jaw tension. The massage releases the masseter and temporalis muscles, which are the primary jaw clenchers. When these release, the jaw hangs freely, the mouth opens wider with less effort, and the vowel space inside the mouth expands. This larger vowel space allows your voice to resonate more fully, producing a richer tone with less effort. Many singers report an immediate improvement in tone quality after jaw release." },
        { text: "Imagine a string attached to the crown of your head, gently pulling you upward. Your spine lengthens. Your chin is level — neither tucked nor lifted. Your neck feels long. Let everything else hang from that string: shoulders, arms, ribcage.", why: "This is the Alexander Technique's 'primary direction' — thinking 'up' without doing 'up.' The visualization creates a subtle postural adjustment without the rigidity of trying to stand up straight. Standing up 'straight' usually creates tension because you are holding yourself in position. Thinking 'up' lets your skeleton do the work while your muscles stay relaxed. The distinction matters enormously for singing: a rigid posture restricts the ribcage and throat, while an aligned-but-relaxed posture frees both. The string image works because it gives your brain a spatial target without specifying which muscles to use — your body figures out the most efficient way to achieve it." },
        { text: "Now stack it all together: soft knees, dropped shoulders, loose jaw, string-from-crown. Take four rib expansion breaths (from v1e2) in this posture. Feel how the posture opens up your breathing capacity.", why: "This integration moment connects posture to breath support. When your body is properly aligned, rib expansion becomes significantly easier because there is no postural compression restricting the ribcage. Many students struggle with rib expansion not because their intercostals are weak, but because their posture is preventing the ribs from moving. The stacked posture removes the postural obstacle, and suddenly the ribs expand more freely. This is why every vocal exercise in this curriculum begins with a posture check — without it, you are working against yourself." },
        { text: "Hum a comfortable note (around G3) for 5 seconds in this stacked posture. Feel the resonance in your chest and face. Now deliberately tense your shoulders up, clench your jaw, and hum the same note. Feel the difference. Then release everything and hum again.", why: "The contrast experiment makes the benefit of good posture viscerally obvious. When you add tension, the hum becomes thinner, tighter, less resonant. When you release it, the hum opens up again. This contrast teaches your body to recognize and reject tension in real-time. Over time, you will develop an internal alarm that goes off when tension creeps in during singing. This body-awareness skill — called proprioceptive monitoring — is one of the hallmarks of trained singers. They are constantly monitoring their physical state and releasing tension before it becomes audible." },
        { text: "Walk around the room for 30 seconds, maintaining the stacked posture. Do not freeze — move naturally. Then stop and hum again. Did the posture survive the movement, or did your old habits sneak back in?", why: "Static posture practice only transfers to real singing if it can survive movement. Singing is not standing still at a microphone — it involves breathing, gesturing, playing guitar, engaging with an audience. If your posture collapses the moment you move, you need more practice. Walking while maintaining alignment trains the vestibular system (balance) and proprioceptive system (body awareness) simultaneously, building postural habits that persist during the dynamic activity of performance. This is why Alexander Technique lessons always include movement — the goal is not a pose, but a pattern that adapts to whatever you are doing." },
        { text: "Final check: in your stacked posture, take a full rib expansion breath and sing 'ah' on G3 for 5 seconds. This should feel easier than it did at the start of the exercise. If it does, your body is learning. Save this feeling — this is your starting position for every vocal exercise from now on.", why: "The final 'ah' is your proof-of-concept. If the posture reset worked, the 'ah' will have more resonance, more ease, and more warmth than the same note would have had before the exercise. Your brain needs this concrete evidence to prioritize posture in the future. Without it, posture correction feels like an abstract chore. With it, posture correction feels like unlocking a tangible improvement. This is the cognitive stage of motor learning: you are conscious of the technique and its effect. With repetition, it becomes associative (you notice deviations) and eventually autonomous (good posture is your default)." }
      ],
      feel: "Your body should feel tall but relaxed. Like a puppet held up by a string from the top of your head, with everything else hanging loose below it. There should be no effort anywhere — just alignment. Your breathing should feel more open than usual, and your voice should feel more resonant with less work.",
      wrong: "If your shoulders creep back up within 30 seconds, you have a chronic tension habit. The shoulder drops need to happen frequently throughout practice, not just once. If you find yourself standing rigidly 'straight,' you have overshot — the goal is aligned, not rigid. If this new posture feels 'wrong' or unnatural, that is proprioceptive drift — your body map is updating. The old posture felt 'right' only because it was familiar, not because it was correct. If your chin is lifted, you are compressing the back of your neck, which restricts the larynx. Level chin, long neck.",
      sarah: "Posture is the most unsexy topic in singing, and it is also the most impactful. I can improve a student's tone by 20% just by fixing their posture. No fancy technique, no exercises — just get the body out of the way and let the voice work. The singers you admire — the ones who look effortless on stage — they all have this alignment happening. It looks like they are not trying because their body is not fighting itself.",
      levelUp: "Can maintain singer's posture through an entire 3-minute exercise without shoulders rising. Hum in stacked posture has noticeably more resonance than hum with tension."
    },
    {
      id: "v1e6", time: 4, title: "Straw Phonation — Advanced SOVT", type: "vocal",
      pitchContour: true,
      what: "Advanced SOVT through a cocktail straw. The narrow opening creates significantly more backpressure than lip trills, which further protects and trains the vocal folds. This exercise was developed by voice scientist Ingo Titze and is now used by vocal therapists, Broadway performers, and pop singers worldwide. Glide through your full range, then transfer the efficient phonation feeling to open vowels.",
      setup: "Standing. Cocktail straw (thin, not wide — coffee stirrer is even better). Glass of water optional for the bubbling variation.",
      referencePitches: getPitchRange("C3", "C4"),
      pianoKeys: { notes: ["C3", "E3", "G3", "A3"], label: "Vocal Range", range: ["C3", "A3"] },
      steps: [
        { text: "Hum into the straw on a comfortable note (around G3). Seal your lips around the straw — no air should escape except through the straw. Feel the backpressure in your throat and nasal cavity.", why: "The narrow straw creates significantly more backpressure than lip trills — roughly 2-3 times more, depending on straw diameter. This increased backpressure does three things simultaneously: it reduces the force with which the vocal folds collide (protecting them from strain), it increases the efficiency of fold vibration (more sound for less effort), and it provides strong tactile feedback in your throat that teaches you what efficient phonation feels like. The narrower the straw, the more backpressure. A coffee stirrer provides more than a regular straw, which provides more than a wide smoothie straw. Start with whatever you have and experiment." },
        { text: "Before you glide, close your eyes and imagine the full arc — your lowest note rumbling in the chest, rising through the sternum, passing through the throat at the passaggio (around A3), entering the mask behind your cheekbones, arriving at the forehead and crown. Now glide from your lowest comfortable note up to your highest on a single breath through the straw. Move slowly — this should take 5-7 seconds. Track the vibration as it physically climbs through your body. Do not force the top — stop when it feels like you are pushing.", why: "The full-range glide through the straw is a diagnostic and a workout simultaneously. It maps your entire range under SOVT protection, revealing where your voice moves freely and where it encounters resistance. The passaggio transition (around A3-Bb3 for your tenor voice) should feel noticeably easier through the straw than it does on open vowels. This is the straw doing its job — the backpressure stabilizes the vocal fold vibration pattern through the register transition, preventing the sudden flip that causes cracks. Over time, your muscles learn this stabilized pattern and can reproduce it without the straw." },
        { text: "Glide back down to your lowest note. Repeat 3 times. Each time, pay special attention to the A3-Bb3 zone — try to make the transition through that zone smoother on each pass.", why: "The break zone is where straw phonation provides the most benefit. Without the straw, the vocal folds struggle to negotiate the transition between thick (chest) and thin (head) vibratory patterns. The straw's backpressure acts as a bridge, keeping the folds vibrating even when they would normally flip or crack. Three passes allows the muscles to learn the transition pattern through repetition. Research shows that 3-5 repetitions of a motor pattern are needed for initial learning, and 50-100 repetitions for consolidation. These three passes start the process; daily practice over weeks completes it." },
        { text: "Remove the straw. Sing 'ooh' on the same glide path — low to high to low. Try to keep the same easy, effortless feeling you had through the straw. The 'ooh' vowel is closest to the straw sensation because the rounded lips partially occlude the vocal tract.", why: "The goal of straw phonation is always to transfer the efficient phonation from straw to open singing. The straw is training wheels, not the destination. 'Ooh' is the ideal transition vowel because the rounded lip position creates a mild SOVT effect, making it the closest open vowel to the straw experience. If the 'ooh' glide feels almost as easy as the straw glide, the transfer is working. If the 'ooh' feels dramatically harder, go back to the straw for two more passes and try again. The transfer improves with practice — you are training your muscles to reproduce the straw's efficiency without the straw's physical assistance." },
        { text: "Try the glide on 'oh' — slightly more open than 'ooh.' Then 'ah' — fully open. Each vowel should be progressively harder to keep smooth through the passaggio. This is normal and expected.", why: "Each progressively open vowel removes more SOVT protection, challenging the vocal folds to maintain efficient vibration with less backpressure assistance. This graduated exposure is how motor learning works in all domains — you start with maximum support (straw), reduce it progressively (ooh, oh, ah), until the skill works independently. If 'ah' feels dramatically harder, that is where your training focus should be. The goal over weeks of practice is for 'ah' to feel as easy as 'ooh,' which should feel as easy as the straw." },
        { text: "If you have water: dip the straw tip into a glass of water (about 1-2 centimeters submerged). Blow bubbles while singing through the straw. The water adds additional resistance. Sustain a note and observe the bubbles.", why: "The water adds a precise, measurable amount of backpressure determined by the depth of submersion. One centimeter of water equals about 1 cm H2O of pressure. This technique, called 'water resistance therapy,' is used in clinical voice rehabilitation. The bubbles also provide instant visual feedback: steady, even bubbles mean steady, even airflow. Uneven, bursting bubbles mean your airflow is inconsistent, which directly correlates with uneven vocal fold vibration. It is biofeedback for breath support — you can literally see whether your support is working." },
        { text: "Water straw challenge: sustain a note through the straw in water for 15 seconds with perfectly even bubbles. No bursts, no pauses, no changes in bubble rate. This requires steady appoggio support from v1e2.", why: "This exercise connects the straw phonation skill to the breath support skill from earlier. Even bubbles for 15 seconds requires the exact same rib expansion and controlled exhale you practiced on 'sss.' The visual feedback of the bubbles makes it impossible to fake — you cannot fool bubbles. If your support wavers, the bubbles show it immediately. This kind of external feedback accelerates motor learning because it closes the feedback loop that your brain needs to calibrate its motor commands. Without feedback, your brain is guessing. With bubbles, your brain can see the result of each adjustment in real-time." },
        { text: "End with one more open glide: remove the straw, low to high to low on 'ooh,' then 'ah.' Notice how much easier both feel compared to before you started the straw exercise. Now set the straw down for a full minute. Then do one final glide from memory — no straw, no warm-up momentum, just you and the feeling you built. That retrieval attempt is worth more than three more reps with the straw.", why: "The final comparison demonstrates the therapeutic effect of straw phonation. Your vocal folds have been exercised under optimal conditions for the past few minutes, and they are now warmed up and functioning more efficiently than before. The open vowels should feel noticeably easier, especially through the passaggio. This post-straw ease is temporary at first — it fades within 30-60 minutes. But with daily practice, the efficient phonation pattern becomes your default, and the ease persists longer and longer until it is simply how your voice works. This is the autonomous stage of motor learning, where the skill requires no conscious thought." }
      ],
      feel: "Through the straw, your voice should feel effortless — the straw does some of the work for you. When you switch to 'ooh,' try to keep that same effortless quality. The sensation to chase is that the sound is 'happening to you' rather than being forced by you. Your throat should feel open and passive, with all the effort living in your torso (breath support) rather than your neck.",
      wrong: "If your face turns red or you feel pressure behind your eyes, you are pushing too hard. The straw needs LESS air than you think — dramatically less. Start with almost no air and add tiny amounts until the sound begins. If no sound comes through, you need slightly more air, but only a tiny bit. If the straw flies out of your mouth, you are using way too much air. If the bubbles in the water are violent and splashing, reduce your airflow by 50% or more.",
      sarah: "Straw phonation is used by Broadway performers between shows, opera singers on tour, and vocal therapists rehabilitating damaged voices. It is the closest thing to a vocal gym machine — resistance training for your voice. Ingo Titze, the scientist who popularized it, calls it the most efficient vocal exercise ever designed. And it takes three minutes. There is no excuse not to do it every day. Keep a straw in your car, in your guitar case, on your desk. Three minutes of straw phonation does more for your voice than thirty minutes of scales.",
      levelUp: "Clean straw glide through full range with smooth passaggio transition, followed by an 'ooh' that maintains the same ease. Even bubbles for 15 seconds if using water."
    },
    {
      id: "v1e7", time: 3, title: "Vocal Fold Health — Hydration & Hygiene", type: "vocal",
      what: "Your vocal folds are two small bands of tissue, each about the size of your thumbnail. They vibrate 100-1000 times per second when you sing. They need to be hydrated, rested, and protected to function well. This exercise teaches the habits that keep your instrument healthy and introduces the concept of systemic versus surface hydration.",
      setup: "Glass of water in hand. Sitting or standing. This is a knowledge-and-practice exercise.",
      steps: [
        { text: "Drink a full glass of water right now. Room temperature, not ice cold. Sip it over 2-3 minutes, do not chug.", why: "Hydration is the single most important factor in vocal fold health. Your vocal folds are covered in a thin layer of mucus that acts as a lubricant, allowing them to vibrate freely. When you are dehydrated, this mucus layer becomes thick and sticky, increasing the friction between the folds and making phonation harder and less efficient. Here is the critical insight: the water you drink now takes 2-4 hours to hydrate your vocal folds because it goes through your digestive system first. This is systemic hydration — it hydrates your entire body, and the vocal folds get their share through the bloodstream. This means you need to hydrate HOURS before you sing, not during. The water you drink now is preparing your voice for later today or tomorrow." },
        { text: "Take a sip of water and hold it in your mouth for 5 seconds before swallowing. Notice the sensation of moisture in your throat as you swallow. Now do a gentle 'steam inhale' — cup your hands around your nose and mouth and breathe slowly through your nose for 30 seconds.", why: "Surface hydration — moisture directly on the vocal fold tissue — acts faster than systemic hydration. Steam, nebulizers, and even the humidity in your breath provide immediate moisture to the folds. The cupped-hands technique creates a small pocket of humid air (your exhaled breath is nearly 100% humidity) that you then inhale, delivering moisture directly to the vocal fold surface. This is a low-tech version of the steam inhalers that professional singers use. It is not as effective, but it is free and available anywhere. The rule of thumb: systemic hydration for long-term health, surface hydration for immediate relief." },
        { text: "Hum gently on a comfortable note for 10 seconds. Notice the quality of the hum — smooth, or scratchy? Clear, or rough? This is your vocal fold hydration diagnostic. A well-hydrated voice hums smoothly. A dehydrated voice sounds rough or scratchy.", why: "The hum test is a quick daily diagnostic for vocal fold condition. Before every practice session, hum a single note and listen. If it sounds clean and smooth, your folds are well-hydrated and ready to work. If it sounds rough, scratchy, or 'gravelly,' your folds need hydration. On rough days, start with extra steam breathing and water, and extend your SOVT warm-up (lip trills, straw phonation) before doing any open singing. SOVT exercises are gentler on dry folds because the backpressure reduces fold collision force. Never push through scratchiness — it is your voice telling you it needs care, not force." },
        { text: "Learn the rule: 'Pee pale, sing well.' If your urine is pale yellow, you are hydrated. If it is dark, you need more water. Aim for 8-10 glasses per day on singing days. Caffeinated drinks count half — they are mild diuretics.", why: "This crude but effective rule gives you an objective hydration metric. Vocal fold hydration cannot be measured directly outside a lab, but urine color correlates well with systemic hydration. The 'count caffeine as half' rule accounts for the diuretic effect of coffee and tea, which cause your body to excrete more water. If you drink 3 cups of coffee and no water, your vocal folds are suffering even if you do not feel thirsty. Thirst is a lagging indicator — by the time you feel thirsty, your vocal folds have already been under-hydrated for an hour. The pale-urine rule catches dehydration before it affects your voice." },
        { text: "Vocal hygiene habits to establish: (1) No screaming or yelling — use your body, not your throat, for volume. (2) No aggressive throat clearing — swallow or sip water instead. (3) No whispering for extended periods — whispering is harder on the folds than normal speech. (4) Rest your voice for 10 minutes after every 50 minutes of singing.", why: "These four habits prevent the most common forms of vocal fold damage in non-professional singers. Screaming and yelling cause the folds to slam together with excessive force, which can create nodules (calluses on the folds). Aggressive throat clearing does the same thing. Whispering, counterintuitively, is harder on the folds than normal speech because the folds are held in a partially closed position that creates turbulent airflow. And continuous singing without rest fatigues the small intrinsic laryngeal muscles, leading to compensatory tension. The 50/10 rule (50 minutes on, 10 minutes off) comes from vocal performance research and matches the fatigue curves of laryngeal muscles." },
        { text: "Practice the swallow-instead-of-clear technique: when you feel the urge to clear your throat, take a sip of water and swallow hard instead. Or do a gentle 'hmm' on a low pitch. Both clear mucus without slamming the folds together.", why: "Throat clearing is one of the most damaging common vocal habits because it forces the vocal folds together with high impact force — like clapping your hands as hard as you can, hundreds of times per day. The swallow technique clears mucus by moving it through the esophagus instead of blasting it off the folds. The gentle low hum vibrates mucus loose without the violent impact. Many voice patients in speech therapy clinics are there primarily because of chronic throat clearing. Breaking this one habit can prevent significant vocal fold damage over a lifetime of singing." },
        { text: "End with 30 seconds of gentle humming at a comfortable pitch. This is your 'fold check-in' — a habit to build into every day. Before morning coffee, hum for 30 seconds and listen to your voice. It is your daily instrument inspection.", why: "Musicians tune their instruments before playing. Singers rarely do. This 30-second morning hum is your daily tuning ritual. It tells you the current state of your vocal folds: well-rested and hydrated (smooth hum), fatigued from the previous day (rough hum), or fighting an illness (very rough or no hum at all). Based on this diagnostic, you can adjust your practice plan — full practice on good days, gentle SOVT only on rough days, complete rest on sick days. This single habit of checking in with your voice every morning prevents more vocal damage than any amount of technique training." }
      ],
      feel: "After this exercise, you should feel informed and empowered about your vocal health. The hum should feel smooth and easy if you are well-hydrated. You should have a glass of water nearby for the rest of your practice session and a plan for staying hydrated throughout the day.",
      wrong: "The most common mistake is thinking hydration only matters right before you sing. It takes HOURS for water to reach your vocal folds. Drink water all day, especially on singing days. The second most common mistake is clearing your throat aggressively — start catching yourself today. Every aggressive clear is like slapping your vocal folds together. Swap it for a sip and swallow.",
      sarah: "I talk about hydration in literally every lesson because it is that important. Your vocal folds are tiny — two little flaps of tissue the size of your thumbnail that vibrate hundreds of times per second. Would you run a machine at high speed without lubrication? That is what singing dehydrated is. Water is not optional for singers. It is maintenance.",
      levelUp: "Established a daily morning hum check-in habit. Drinking water consistently throughout the day. Using the swallow technique instead of throat clearing."
    },
    {
      id: "v1e8", time: 3, title: "Breathing Patterns — Speaking vs. Singing", type: "vocal",
      metronome: 60,
      what: "Your body breathes differently for speaking, singing, and normal breathing. This exercise makes those differences conscious. Speaking uses shallow, frequent breaths. Singing demands deeper, less frequent breaths with controlled exhale. Normal breathing is passive and automatic. Understanding these three modes lets you switch to 'singing breathing' deliberately.",
      setup: "Standing. One hand on belly, one on ribs. Recording yourself is optional but helpful.",
      steps: [
        { text: "Breathe normally for 30 seconds. Do not try to breathe 'correctly' — just let your body breathe automatically. Count how many breaths you take. Normal resting rate is 12-20 breaths per minute.", why: "Your baseline breathing rate establishes the 'automatic' pattern your body defaults to. This is tidal breathing — shallow, low-effort, approximately 500ml of air per breath. Your body manages this without conscious input, which is exactly the problem for singing: if you do not deliberately switch to a different breathing mode, your body will default to tidal breathing during singing, which provides insufficient airflow and support for sustained phrases. You need to know what automatic feels like so you can recognize when you have slipped back into it during a song." },
        { text: "Now speak a sentence at a conversational pace: 'I went to the store and bought some groceries and then I came home and made dinner.' Notice where you breathed. Notice how quick and shallow the breaths were.", why: "Conversational speech uses a different breathing pattern: quick inhalations between phrases, with exhale duration matching phrase length (usually 2-5 seconds). The breaths are shallow because you only need a small amount of air for short phrases. Your larynx, jaw, and lips do most of the work in speech, and the breath just provides a carrier airflow. This is fine for talking, but it fails for singing because singing demands sustained, steady airflow for longer phrases (often 8-15 seconds), greater subglottic pressure for projection, and precise airflow control for pitch and dynamics." },
        { text: "Now sing a long phrase: the first line of 'Happy Birthday.' Sing it on one breath if you can. Notice how the breath you took was deeper, and how you had to control the exhale to make it through the phrase.", why: "Your body automatically adjusts its breathing when you shift from speaking to singing — you take a larger breath and release it more slowly. This is partially learned (from years of singing along to music) and partially reflexive (your brain knows it needs more air for longer phonation). The problem is that this automatic adjustment is usually not enough. Untrained singers take a bigger breath but do not control the exhale, so they run out of air at the same point regardless of breath size. The solution is not to breathe MORE but to exhale MORE EFFICIENTLY — which is exactly what appoggio (rib expansion breathing) does." },
        { text: "Practice the 'singing breath': inhale through your nose for 3 counts with rib expansion (ribs out, belly slightly forward). Hold for 1 count. Exhale on 'sss' for 15 counts. The ratio is approximately 1:5 — inhale is quick, exhale is long.", why: "The 1:5 ratio approximates the breathing pattern of trained singers. A typical singing phrase lasts 8-15 seconds, but the inhalation between phrases is often less than 2 seconds (sometimes less than 1 second). This asymmetry is the opposite of normal breathing (which is roughly 1:1) and requires training to execute smoothly. The hold at the top of the breath is the moment where the singer 'sets' the appoggio — engaging the intercostals and diaphragm in the position that will control the exhale. Without this set, the exhale collapses into an uncontrolled rush of air." },
        { text: "Now try the singing breath with actual singing: take a singing breath (3 counts in, 1 count hold). Before you start, hear the ascending line internally — C3 in the chest, D3-E3 climbing through the upper chest, F3-G3 arriving at the throat and jaw. Then sing 'ooh' ascending C3-D3-E3-F3-G3, one note per beat at 60 BPM, then descending G3-F3-E3-D3-C3. All on one breath. 10 notes, approximately 10 seconds. Feel the vibration rise and fall through your body with each note.", why: "This applies the breathing pattern to real singing. Ten seconds of sustained singing on one breath is a reasonable Level 1 target. If you run out of air before the last note, your exhale is not controlled enough — you are releasing too much air on the early notes and running dry at the end. The fix is not to take a bigger breath but to use less air per note. SOVT exercises teach this efficiency; the singing breath exercise gives you the opportunity to apply it. Notice whether the appoggio hold from v1e2 helps — your ribs staying expanded should make the exhale last longer." },
        { text: "Experiment with 'catch breaths' — the quick, silent inhalations singers use between phrases. Sing C3-D3-E3 on 'la,' take a tiny catch breath (a quick sniff through your nose, less than half a second), then sing F3-G3 on 'la.' The catch breath should be inaudible.", why: "Catch breaths are essential for real-world singing because songs rarely have long pauses between phrases. The skill is taking in enough air in a fraction of a second to sustain the next phrase, without making an audible gasp. The nasal sniff is quieter than a mouth gasp and slightly more efficient at filling the lower lungs. Most untrained singers take audible, gasping breaths between phrases that interrupt the musical flow. Training the silent catch breath makes your breathing invisible to the listener, which is a hallmark of professional singing. The Allah-Las and DOPE LEMON tracks you love have this quality — you never hear the singer gasp between lines." },
        { text: "Combine everything: take a singing breath, sing a 10-second phrase, take a catch breath, sing another 5-second phrase, take another catch breath, sing a final 5-second phrase. Total: approximately 20 seconds of singing with two invisible breath points.", why: "This simulates actual song singing — multiple phrases connected by catch breaths, all managed by appoggio support. The challenge is maintaining rib expansion and diaphragm engagement through the catch breaths. Many students let their support collapse when they breathe in, then have to re-establish it for the next phrase. The goal is continuous support — the ribs stay expanded even during the catch breath, and the diaphragm re-engages instantly. This continuity is what separates phrase-by-phrase singing from flowing, connected musical performance." }
      ],
      feel: "The singing breath should feel deliberate, deep, and controlled — fundamentally different from how you breathe when talking or resting. The catch breath should feel like a tiny sip of air that barely interrupts the singing. Overall, you should feel like you are managing an airflow system, not just breathing.",
      wrong: "If you hear yourself gasping between phrases, the catch breath is too large or too forceful. Make it smaller and quieter. If you run out of air before the phrase ends, you are releasing too much air — tighten your appoggio (keep ribs expanded more firmly). If you feel dizzy, you are hyperventilating — take fewer practice breaths between rounds and let your body normalize.",
      sarah: "The difference between a good singer and a great singer is usually breathing. Not pitch, not tone, not style — breathing. When I watch a great singer perform, I can not tell when they breathe. It is invisible. When I watch a beginning singer, all I see is breathing — gasps, shoulder raises, running out of air. Making breathing invisible is the goal of all of Level 1. When you get there, everything else becomes possible. In your final two minutes, try mixing this breathing work with something from an earlier exercise — posture resets or rib expansion. Blending skills from different sessions is where real integration happens.",
      levelUp: "Can sing a 10-second phrase with controlled exhale and appoggio support. Catch breaths are inaudible to a listener standing 3 feet away."
    },
    {
      id: "v1e9", time: 3, title: "Resonance Location Awareness", type: "vocal",
      what: "Your voice resonates in different parts of your body depending on pitch, vowel, and placement. This exercise maps your personal resonance landscape — where you feel vibration for different sounds. Building this somatosensory map is the foundation of using 'feel' to monitor your voice, which is how all trained singers operate.",
      setup: "Standing. Hands free to touch different parts of your face, chest, and head. Quiet room.",
      referencePitches: getPitchRange("C3", "G4"),
      pianoKeys: { notes: ["C3", "E3", "G3", "A3"], label: "Vocal Range", range: ["C3", "A3"] },
      steps: [
        { text: "Sing 'ah' on C3 (a low chest-voice note). Place your hand flat on your sternum (center of chest). Feel for vibration — a warm, heavy buzz that spreads through your ribs. This is the body address of your low chest zone. The sound does not just come from your throat; it lives here, behind the bone, radiating outward.", why: "Low chest-voice notes resonate strongly in the chest cavity because the large, thick vocal fold vibration pattern produces low-frequency sound waves that couple with the large air space of the thorax. This chest vibration is why it is called 'chest voice' — the name comes from where singers feel the resonance, not where the sound is produced (it is always produced at the larynx). Learning to feel this chest buzz gives you a physical anchor for chest voice that is more reliable than trying to hear the difference. Your ears can be fooled by room acoustics and monitoring equipment. The feeling in your chest is always available and always accurate." },
        { text: "Sing 'ee' on C3 with the same hand on your chest. Notice: the chest vibration is weaker on 'ee' than on 'ah,' even at the same pitch. Now touch your nose bridge — 'ee' vibrates more there.", why: "Different vowels direct resonance to different locations because vowel shape changes the acoustic properties of your vocal tract. 'Ah' opens the throat wide, creating a large resonating chamber that couples with the chest. 'Ee' narrows the throat and raises the tongue, directing more energy into the nasal and sinus cavities. This is formant tuning — the same pitch resonates differently depending on the shape of the space above the vocal folds. Understanding this gives you control over tonal color: more 'ah' space equals warmer, more 'ee' space equals brighter. The laid-back warmth of DOPE LEMON vocals comes from 'ah'-leaning vowel shapes. The cutting brightness of early punk comes from 'ee'-leaning shapes." },
        { text: "Ascend slowly from C3 to G3 on 'ah.' As you climb, move your hand from your chest upward: sternum at C3, collarbone at E3, throat at F3, chin at G3. Feel the vibration migrate upward as pitch increases. You are walking up the body map — the vibration-rising pathway that every note you sing will follow. Low notes rumble in the chest; mid-range notes warm the throat and jaw; higher notes will eventually reach the mask and forehead.", why: "As pitch increases, the dominant resonance shifts from the chest cavity to the head cavities. This migration is a physical manifestation of the register transition — the vibration literally moves upward in your body as the vocal folds thin out and the sound shifts from chest-dominant to head-dominant. Mapping this migration creates a physical roadmap of your registers. Instead of thinking 'am I in chest or head voice?' you can feel it: vibration in the chest means chest voice, vibration in the face means head voice, vibration in between means mix voice. This somatosensory approach to register awareness is more reliable and faster than the auditory approach." },
        { text: "Sing 'ng' (as in 'sing') on E3. Touch the bridge of your nose, your forehead, and the top of your head. The 'ng' should produce strong buzzing in your nose and sinuses — possibly even a ticklish feeling.", why: "The 'ng' consonant routes nearly all acoustic energy through the nasal cavity, maximizing nasal resonance. This is an exaggerated version of 'forward placement' — the vocal technique of directing resonance into the sinuses and nasal cavity for a brighter, more projecting tone. By feeling where 'ng' vibrates most strongly, you identify the physical locations associated with forward placement. These are the same locations that should buzz when you sing well — the nose bridge, the cheekbones, and the hard palate behind your upper teeth. Forward placement is not about singing through your nose; it is about feeling the sympathetic vibration of your sinus cavities, which indicates efficient resonance." },
        { text: "Alternate: sing 'ah' on E3 (chest resonance) then immediately 'ng' on E3 (nasal resonance), back and forth 5 times. Same pitch, radically different resonance location. Feel the vibration jump between your chest and your nose.", why: "This contrast exercise trains your ability to shift resonance location deliberately. In real singing, you blend these resonance locations to create different tonal colors. A warm verse might use more 'ah' (chest) resonance. A bright, cutting chorus might use more 'ng' (nasal/forward) resonance. The ability to blend these at will is what gives singers like Angus Stone their tonal palette — he moves between chest-warm and head-bright within a single phrase, creating emotional arcs through resonance, not volume. By alternating rapidly, you are teaching your muscles to switch between configurations quickly, which is the foundation of real-time tonal control." },
        { text: "Hum (lips closed, 'mmm') on G3 and systematically touch: chest, throat, jaw, lips, nose, cheekbones, forehead, crown. Rate each location 1-5 for vibration intensity. Your 'resonance map' on G3 will be different from someone else's — this is personal data about your instrument. You are learning to feel your voice as a physical landscape, not just a sound. Every note you will ever sing has a body address, and you are drawing the map right now.", why: "Every voice has a unique resonance profile based on the size and shape of the singer's skull, sinuses, oral cavity, and chest. There is no 'correct' resonance map — only YOUR resonance map. By rating vibration intensity at different locations, you build a personalized reference that tells you where YOUR voice resonates most strongly at different pitches. This data becomes invaluable in later levels when you are trying to modify your tone: you will know that increasing nose-bridge vibration brightens your sound, while increasing chest vibration warms it. This is the somatosensory dominance principle — trained singers make 76% of their vocal adjustments based on FEEL, not sound. You are building the feeling vocabulary right now." },
        { text: "Repeat the resonance map on C3, E3, and A3. Notice how the map changes at different pitches — lower notes resonate more in the chest, higher notes more in the head. A3 (your passaggio) may feel ambiguous — resonance split between chest and head. That ambiguity IS the passaggio. Before you finish: what did you notice that surprised you? Name one sensation you did not expect. That noticing IS the skill.", why: "Mapping resonance at three different pitches gives you a three-dimensional understanding of your instrument. C3 should be chest-dominant, A3 should be ambiguous or split, and if you can reach it comfortably, E4 would be head-dominant. The passaggio pitch (A3 for you) feels ambiguous because the vocal folds are in transition between thick and thin vibratory patterns, and the resonance is genuinely split between the chest and head cavities. This ambiguity is not a problem to solve — it is the nature of the passaggio. Learning to feel comfortable with that ambiguous resonance is one of the skills of Level 2." }
      ],
      feel: "You should finish this exercise with a clear physical awareness of where your voice 'lives' at different pitches and on different vowels. It should feel like you have developed a new sense — a vibration-awareness that you did not have before. The chest buzz, the nose buzz, the forehead buzz — these are the physical landmarks you will use to navigate your voice going forward. You are building the vibration-rising map that will guide every note you sing: low chest (sternum, ribs) for E2-A3, the transitional throat-jaw zone around the passaggio, and the mask (cheeks, nose bridge, forehead) for everything above. This body-location awareness is not a metaphor — Zamorano 2025 found that body awareness predicts pitch accuracy (R²=0.41). The singers who feel where each note lives sing more accurately than those who only listen.",
      wrong: "If you cannot feel any vibration anywhere, you may be singing too quietly. Increase your volume slightly — vibration becomes more noticeable at moderate volume. If you feel vibration in your throat, you may be holding tension there — release and try again. The throat should feel open and relaxed, not buzzy. Throat buzz often indicates constriction.",
      sarah: "This exercise is the beginning of learning to FEEL your voice instead of just hearing it. The best singers in the world do not listen to themselves — they feel themselves. They know where the vibration is, and they adjust based on feel. This sounds mystical, but it is just neuroscience: your brain processes somatosensory information (physical feeling) faster than auditory information (sound). So trained singers who use feel can make corrections faster than those who rely on hearing. You are building that faster correction pathway right now.",
      levelUp: "Can identify and describe resonance locations for at least 3 pitches across your range. Can feel the difference between chest resonance and nasal resonance on the same pitch."
    },
    {
      id: "v1e10", time: 4, title: "Level 1 Integration — The Full Warm-Up", type: "vocal",
      pitchContour: true,
      recorder: true,
      what: "Combine everything from Level 1 into a single, flowing warm-up sequence. This is the routine you will use before every practice session and every performance from now on. It takes about 4 minutes and prepares your body, breath, and voice for anything you want to sing. By the time you reach Level 10, this warm-up will be automatic — muscle memory doing the work while your mind focuses on the music.",
      setup: "Standing. Water nearby. Straw in reach. This is your complete warm-up protocol.",
      referencePitches: getPitchRange("C3", "A3"),
      pianoKeys: { notes: ["C3", "E3", "G3", "A3"], label: "Vocal Range", range: ["C3", "A3"] },
      steps: [
        { text: "Posture Reset (30 seconds): soft knees, shoulder drops (3x), jaw massage, string-from-crown. Four rib expansion breaths. This is your launch position.", why: "Starting with posture ensures that every subsequent exercise happens in the optimal physical configuration. Posture errors compound — a tight jaw during the warm-up leads to a tight jaw during singing, which leads to restricted resonance and vocal fatigue. The 30-second posture reset catches and corrects these issues before they cascade. After doing this dozens of times, the posture check becomes nearly instantaneous — your body recognizes the 'singing posture' state and drops into it within a few seconds. This is the autonomous stage of motor learning, and it is the goal for all foundational skills." },
        { text: "Vagal Humming (45 seconds): close your eyes, three extended-exhale breaths (4 in, 6 out). Before humming, hear C3 in your mind — feel where it will live in your body. Then hum on C3 for 15 seconds. The vibration settles behind the sternum, a warm buzz that grounds you in the chest — the body address of home. This shifts your nervous system into parasympathetic mode.", why: "The vagal activation prepares your neurological state for singing. Performance anxiety, daily stress, and even caffeine can push your nervous system into sympathetic (fight-or-flight) mode, which tightens the larynx and reduces vocal flexibility. The humming sequence counteracts this, creating the calm-but-alert state that supports free, expressive singing. Over time, this humming ritual becomes a trigger — your body associates the hum with the singing state, and the calm focus arrives faster. Pavlovian conditioning in service of vocal performance." },
        { text: "Lip Trills (60 seconds): trill on C3, D3, E3 (5 seconds each). Then glide C3 to G3 and back, 3 times. Final glide extending to A3 if it feels comfortable.", why: "Lip trills warm up the vocal folds under SOVT protection — maximum benefit with minimum risk. Starting on sustained notes warms the folds at a stable pitch, and the glides extend the warm-up through your working range. The A3 extension probes the passaggio, preparing the folds for the register transition work in Level 2. After Level 1, you should be able to trill smoothly from C3 to G3. The A3 extension may still feel wobbly, and that is fine — it gives you something to improve." },
        { text: "Straw Phonation (45 seconds): full-range glide through the straw, up and down, 2 times. Focus on smooth passaggio transition. Then remove the straw and glide on 'ooh,' same path.", why: "The straw phonation builds on the lip trill warm-up, adding more SOVT backpressure for deeper vocal fold conditioning. The transfer to 'ooh' bridges the gap between SOVT and open singing. By this point in the warm-up, your voice should feel noticeably different from when you started — warmer, more resonant, more flexible. The straw-to-open transfer ensures that these benefits carry into your actual singing, not just your warm-up exercises." },
        { text: "Chest Voice Check (30 seconds): three 'Hey!' exclamations with belly engagement — feel the pulse behind the sternum with each one. Then hear G3 internally before you sing it: imagine the buzz arriving at the upper chest and lower throat. Sustain 'Hey' on G3 for 5 seconds. The vibration should live right at the collarbone line — chest voice's upper address. Confirm that diaphragm engagement is present and consistent.", why: "The chest voice check confirms that your primary register is activated and supported. After the gentle SOVT warm-up, it is important to re-engage the diaphragm and confirm that chest voice is grounded and present. This check also serves as a daily diagnostic — if the 'Hey!' feels weak or disconnected today, you may need more warm-up time before moving to singing exercises." },
        { text: "Resonance Scan (30 seconds): hum on C3 and feel the vibration settle into your sternum. Hum on E3 and feel it climb to your throat and jaw. Hum on G3 and feel it arrive behind your nose and cheekbones. Three pitches, three body addresses. This is your vibration-rising map — the physical landscape your voice lives in.", why: "The resonance scan confirms that your somatosensory awareness is active — that you are feeling your voice, not just hearing it. This scan becomes a quick diagnostic: if you cannot feel chest vibration on C3 or face vibration on G3, something is off (dehydration, tension, fatigue) and you may need to adjust your practice plan. Building this diagnostic habit early means you will always know the current state of your instrument before you ask it to perform." },
        { text: "Singing Check (30 seconds): sing 'Happy Birthday' once through, at conversational volume, with good posture and breath support. Compare this to your diagnostic recording from v1e0. Does it sound and feel better?", why: "The singing check is the proof that the warm-up worked. 'Happy Birthday' is your benchmark melody from the diagnostic pre-test. Singing it again after the warm-up reveals the cumulative effect of posture, breathing, SOVT, and resonance work. Over the weeks of Level 1 practice, the difference between your cold 'Happy Birthday' and your warmed-up 'Happy Birthday' will grow — the warm-up version will consistently sound fuller, more supported, and more resonant. This growing gap is evidence of skill development, not just warm-up effect." },
        { text: "Drink water. You are ready to sing. From now on, this 4-minute sequence is your pre-singing ritual. Do it every time — before practice, before performing, before singing in the car. Consistency is more important than perfection.", why: "The integration exercise becomes a habit through repetition. Research on habit formation suggests that 21-66 days of consistent practice are needed to make a behavior automatic. By doing this warm-up every time you sing, you are building a vocal hygiene habit that will protect and prepare your voice for the rest of your singing life. The 4-minute time investment pays dividends in vocal health (reduced strain), vocal quality (better tone from the first note), and confidence (knowing your voice is ready). Professional singers treat their warm-up as non-negotiable — it happens every time, no exceptions, no shortcuts." }
      ],
      feel: "After the integration warm-up, your voice should feel like a well-tuned engine: warm, responsive, ready for anything. The transition from cold to warmed-up should be noticeable and satisfying. Your body should feel aligned but relaxed, your breathing deep and controlled, and your voice resonant and easy. This is your 'singing state' — learn to recognize it, because it is the starting line for every exercise in every level that follows. Notice what has happened: you have moved through the entire body-as-instrument — posture aligned the frame, breathing activated the engine, humming woke the resonators, and the resonance scan confirmed that vibration is flowing to the right places. The full cycle — feel the body, produce the sound, compare the sensation — is already running. You just completed it for the first time as one integrated act.",
      wrong: "If the 4-minute warm-up feels rushed, take 5-6 minutes. If it feels too long, you are probably skipping steps — do all of them, even when they feel unnecessary. The most dangerous moment in vocal practice is thinking you do not need to warm up. You always need to warm up. Even Beyonce warms up. Especially Beyonce warms up. Always end the warm-up on something that felt good — a clean trill, a resonant hum. Your brain encodes the ending as the summary of the session.",
      sarah: "This warm-up is your gift to your voice. It costs 4 minutes, and it prevents strain, improves tone, and builds the foundation for everything else. I have students who have been singing for ten years and still do this warm-up before every session. Not because they need it — because they respect their instrument. That respect is what separates hobbyists from artists. You are becoming an artist."
    },
    {
      id: "v1e11", time: 5, title: "Full-Range Siren", type: "vocal",
      drone: { root: "A", octave: 2, texture: "pure" },
      referencePitches: getPitchRange("C3", "G4"),
      pianoKeys: { notes: ["C3", "E3", "G3", "A3"], label: "Vocal Range", range: ["C3", "A3"] },
      pitchContour: true,
      recorder: true,
      what: "Wide-range siren on lip trill from your lowest comfortable note to your highest and back. Pfordresher's 2025 research found that wide-range training improves pitch accuracy MORE than narrow-range practice — counterintuitively, stretching across your full range builds better pitch control even in the comfortable middle. This siren is both warm-up and pitch training. Let your body MOVE with the siren — sway, raise your arms as pitch rises, lower them as it falls. Research on embodied cognition (2025 Journal of Voice) shows that body movement during singing improves vocal performance through external attentional focus.",
      setup: "Standing. No guitar. Straw nearby for SOVT version.",
      steps: [
        { text: "Before the first siren: inhale for 4 counts, then hum-sigh for 6 counts, letting the sound fall from high to low like a gentle exhale. Repeat three times. This is not relaxation theater — it is physiological preparation, waking up the vagus nerve that directly innervates your vocal folds. Then start on your lowest comfortable note (around C3). Begin a lip trill. Slowly slide UP to the highest note you can reach without straining. Let it take 5 full seconds. Then slide back down. One continuous siren. As you rise, let your body rise too — stand taller, lift your chin slightly, let your arms float upward. As you descend, settle back down.", why: "The full-range glide trains the auditory-motor loop across maximum pitch distance. Pfordresher & Greenspon (2025) found that wide-range pitch training produced the ONLY significant improvements in single-pitch matching — narrow-range training showed no significant effect. The body movement creates an external focus of attention (Wulf 2025), which improves motor performance by engaging automated control processes." },
        { text: "Repeat 3 times. Each time, try to extend slightly higher or lower. The lip trill protects your vocal folds (SOVT) while you explore the edges of your range. Notice where your passaggio is — the siren will wobble or thin there around A3-B3. That is the transitional zone where the vibration leaves the chest and enters the throat and jaw. The wobble is not a flaw; it is the body negotiating the handoff between registers.", why: "Repeated full-range traversals build the brain's pitch map — the sensorimotor model of where every pitch lives in your range. The wobble at the passaggio is the register transition happening in real time. With practice, the wobble smooths as the TA-CT muscle balance becomes more coordinated." },
        { text: "Now try on 'ooh' instead of lip trill — same full range siren, but with an open vowel. This is harder because the SOVT protection is gone. If your voice cracks at the passaggio, that's fine — the crack tells you exactly where the register transition happens.", why: "The lip-trill-to-open-vowel progression mirrors the warm-up pattern from v1e10. By moving from SOVT to open vowel, you're testing whether the benefits of the lip trill transfer to actual singing. Any crack or break that appears on 'ooh' but not on the lip trill reveals where your technique still needs the acoustic scaffolding." },
        { text: "Straw phonation version: do the full-range siren through a cocktail straw. The straw adds backpressure that keeps the folds adducted efficiently. You should be able to reach slightly higher through the straw than on an open vowel. That extra range is your 'potential range' — achievable with better technique.", why: "The straw creates semi-occlusion that raises the supraglottic pressure, keeping the vocal folds in contact during high-frequency vibration that would otherwise cause them to blow apart. The extra range you achieve through the straw represents what your instrument CAN do — the gap between straw range and open-vowel range is your current technical limitation, which closes with practice." },
        { text: "Self-assessment: What was your lowest comfortable note? Your highest on lip trill? Highest on 'ooh'? Highest through straw? Write down all four. These numbers will improve weekly. The straw-to-open gap is your most actionable metric — it tells you how much range your technique is currently leaving on the table.", why: "Quantified self-assessment with four specific measurements gives Gene concrete, trackable progress data. The straw-to-open gap is particularly actionable because it represents technique limitations, not physical ones — technique can improve; vocal anatomy is fixed." }
      ],
      feel: "The siren should feel like stretching — reaching into the full space of your voice with the same gentle effort as a morning stretch. Let your body participate. When your arms rise with the pitch, you're creating a mind-body connection that reinforces the pitch sensation physically. Track the vibration as you ascend: the siren begins in the chest (sternum buzz), passes through the throat and jaw at the passaggio, and arrives in the mask and crown at the top. Coming back down, the vibration settles from forehead through mask through throat and home to the chest. This is the vibration-rising map in motion — your body telling you where every pitch lives. If it feels like straining, you're pushing too hard — sirens should be gentle.",
      wrong: "If you're forcing the top notes, stop and back off. The siren should feel effortless throughout. Straining at the top defeats the purpose — you're training range through repetition, not through force. If the lip trill stops trilling at high pitches, you've exceeded your trill range — switch to 'ooh' or the straw.",
      sarah: "Gene, this is the single exercise the 2025 research says matters most for pitch accuracy. Wide-range training — not careful mid-range drilling — is what actually improves your pitch control everywhere. Five seconds up, five seconds down, full range. Do it every warm-up.",
      levelUp: "Can complete the full integration warm-up in 4 minutes with all elements present. Voice sounds noticeably warmer and more resonant after warm-up compared to cold start. Perform full-range sirens with body movement for wide-range pitch training. This is your graduation requirement for Level 1."
    }
  ]
};
